function validateNom(e){let r=/^[- A-Za-zÀ-ÖØ-öø-ÿ]+$/,s=document.getElementById("user_form_"+e),n=document.getElementById(e+"_error");return r.test(s.value)?(s.classList.remove("border-danger"),n.classList.add("invisible"),n.innerHTML="",!0):(s.classList.add("border-danger"),n.innerHTML="Veuillez renseigner un <strong>"+e+"</strong></em> valide.",n.classList.remove("invisible"),!1)}function validateEmail(e){let r=/^[\w-+.]+@[\w-.]+\.[\w.]+$/,s=document.getElementById("email_error");return r.test(e.value)?(e.classList.remove("border-danger"),s.classList.add("invisible"),s.innerHTML="",!0):(e.classList.add("border-danger"),s.innerHTML="Veuillez renseigner un <strong>Email</strong> valide.",s.classList.remove("invisible"),!1)}function validatePassword(e){let r=document.getElementById("password1_error");return e.value.length>=8?(e.classList.remove("border-danger"),r.classList.add("invisible"),r.innerHTML="",!0):(e.classList.add("border-danger"),r.innerHTML="Veuillez renseigner un <strong>Mot de passe</strong> d'au moins 8 caractères.",r.classList.remove("invisible"),!1)}function validateConfirmPassword(e,r){let s=document.getElementById("password2_error");return e.value!=r.value?(e.classList.add("border-danger"),r.classList.add("border-danger"),s.innerHTML="Les <strong>Mots de passe</strong> ne correspondent pas.",s.classList.remove("invisible"),!1):(e.classList.remove("border-danger"),r.classList.remove("border-danger"),s.classList.add("invisible"),s.innerHTML="",!0)}function validateCGU(e){let r=document.getElementById("cgu_error");return e.checked?(e.classList.remove("border-danger"),r.innerHTML="",r.classList.add("invisible"),!0):(e.classList.add("border-danger"),r.innerHTML="Vous devez accepter les <em><strong>CGU</strong></em> de Green Goodies",r.classList.remove("invisible"),!1)}let inscription=document.querySelector("section.gg-inscription");if(inscription){var erreurs=0;let e=document.querySelector("form");e&&e.addEventListener("submit",r=>{r.preventDefault();let s=document.getElementById("user_form_email"),n=document.getElementById("user_form_password_first"),t=document.getElementById("user_form_password_second"),i=document.getElementById("user_form_CGU");validateNom("prenom")||erreurs++,validateNom("nom")||erreurs++,validateEmail(s)||erreurs++,validatePassword(n)||erreurs++,validateConfirmPassword(n,t)||erreurs++,validateCGU(i)||erreurs++,erreurs||e.submit(),erreurs=0})}